import http from "node:http";

function splitPath(pathname) {
  return pathname.split("/").filter(Boolean);
}

function createResponseHelpers(response) {
  response.status = function status(code) {
    response.statusCode = code;
    return response;
  };

  response.json = function json(payload) {
    const body = JSON.stringify(payload);
    response.setHeader("content-type", "application/json");
    response.end(body);
  };

  response.send = function send(payload) {
    response.end(payload);
  };
}

function matchPath(pattern, pathname) {
  if (pattern === "*" || pattern === pathname) {
    return { matched: true, params: {} };
  }

  const patternSegments = splitPath(pattern);
  const pathSegments = splitPath(pathname);
  if (patternSegments.length !== pathSegments.length) {
    return { matched: false, params: {} };
  }

  const params = {};
  for (let index = 0; index < patternSegments.length; index += 1) {
    const patternSegment = patternSegments[index];
    const pathSegment = pathSegments[index];
    if (patternSegment.startsWith(":")) {
      params[patternSegment.slice(1)] = decodeURIComponent(pathSegment);
      continue;
    }

    if (patternSegment !== pathSegment) {
      return { matched: false, params: {} };
    }
  }

  return { matched: true, params };
}

function stripPrefix(pathname, prefix) {
  if (!prefix || prefix === "/") {
    return pathname;
  }
  if (!pathname.startsWith(prefix)) {
    return null;
  }
  const stripped = pathname.slice(prefix.length);
  return stripped.startsWith("/") ? stripped : `/${stripped}`;
}

function createLayer(method, path, handler, isRouter = false) {
  return { method, path, handler, isRouter };
}

function createApp() {
  const layers = [];

  async function app(request, response, out) {
    createResponseHelpers(response);

    const requestUrl = new URL(request.url, "http://localhost");
    request.path = requestUrl.pathname;
    request.query = Object.fromEntries(requestUrl.searchParams.entries());
    request.params = request.params || {};
    request.header = (name) => request.headers[name.toLowerCase()];

    let index = 0;
    const next = async (error) => {
      const layer = layers[index];
      index += 1;

      if (!layer) {
        if (out) {
          return out(error);
        }
        if (error) {
          response.status(error.statusCode || 500).json({ error: error.message || "internal_error", details: error.details || null });
          return;
        }
        response.status(404).json({ error: "not_found", path: request.path });
        return;
      }

      if (error) {
        if (layer.handler.length === 4) {
          return layer.handler(error, request, response, next);
        }
        return next(error);
      }

      if (layer.handler.length === 4) {
        return next();
      }

      if (layer.method === "USE") {
        if (layer.isRouter) {
          const strippedPath = stripPrefix(request.path, layer.path);
          if (strippedPath === null) {
            return next();
          }
          const originalPath = request.path;
          request.path = strippedPath || "/";
          request.url = `${request.path}${requestUrl.search}`;
          return layer.handler(request, response, async (routerError) => {
            request.path = originalPath;
            request.url = `${originalPath}${requestUrl.search}`;
            return next(routerError);
          });
        }

        if (layer.path !== "/" && !request.path.startsWith(layer.path)) {
          return next();
        }
        return layer.handler(request, response, next);
      }

      if (layer.method !== request.method) {
        return next();
      }

      const { matched, params } = matchPath(layer.path, request.path);
      if (!matched) {
        return next();
      }

      request.params = params;
      return layer.handler(request, response, next);
    };

    return next();
  }

  app.use = (path, handler) => {
    if (typeof path === "function") {
      layers.push(createLayer("USE", "/", path));
      return app;
    }
    layers.push(createLayer("USE", path, handler, Boolean(handler.__isRouter)));
    return app;
  };

  app.get = (path, handler) => {
    layers.push(createLayer("GET", path, handler));
    return app;
  };

  app.post = (path, handler) => {
    layers.push(createLayer("POST", path, handler));
    return app;
  };

  app.listen = (port, callback) => http.createServer(app).listen(port, callback);

  return app;
}

function Router() {
  const router = createApp();
  router.__isRouter = true;
  return router;
}

function json() {
  return async (request, _response, next) => {
    if (!["POST", "PUT", "PATCH"].includes(request.method)) {
      request.body = {};
      return next();
    }

    const contentType = request.headers["content-type"] || "";
    if (!contentType.includes("application/json")) {
      request.body = {};
      return next();
    }

    let body = "";
    for await (const chunk of request) {
      body += chunk;
    }

    if (!body) {
      request.body = {};
      return next();
    }

    try {
      request.body = JSON.parse(body);
      return next();
    } catch {
      const error = new Error("invalid_json");
      error.statusCode = 400;
      return next(error);
    }
  };
}

const express = Object.assign(createApp, { Router, json });
export default express;
